texttool_globals_toast___favorite_list_is_full = TextObject(bs_BA="Ovaj sadržaj se više ne može memorirati jer je spisak favorita\npun.", cs_CZ="Tento obsah již nebylo možné uložit, protože seznam\noblíbených je plný.", da_DK="Dette indhold kan ikke længere gemmes, da favoritlisten er fuld.", de_DE="Dieser Inhalt kann nicht mehr gespeichert werden, da die\nFavoritenliste voll ist.", el_GR="Δεν είναι πλέον εφικτή η αποθήκευση αυτού του\nπεριεχομένου, διότι η λίστα αγαπημένων είναι πλήρης.", en_GB="This content could not be stored because the favourites list\nis full.", es_ES="Este contenido no se puede memorizar porque la lista de\nfavoritos está llena.", fi_FI="Tätä sisältöä ei enää voida tallentaa, sillä suosikkilista on täynnä.", fr_FR="Ce contenu ne peut plus être mémorisé car la liste des\nfavoris est pleine.", hr_HR="Sadržaj se više ne može pohraniti jer je popis favorita pun.", hu_HU="Ez a tartalom nem menthető, mert a Kedvencek lista megtelt.", it_IT="Non è più possibile memorizzare questo contenuto perché la\nlista dei preferiti è piena.", nl_NL="Deze inhoud kan niet meer worden opgeslagen, omdat de\nfavorietenlijst vol is.", no_NO="Kan ikke lenger lagre dette innholdet fordi favorittlisten er full.", pl_PL="Nie można zapisać tej treści, ponieważ lista Ulubionych jest\npełna.", pt_PT="Este conteúdo já não pode ser guardado, pois a lista de\nfavoritos está cheia.", ro_RO="Acest conţinut nu mai poate fi memorat, deoarece lista de\nfavorite este plină.", ru_RU="Этот контент больше не может быть сохранен, так как\nсписок избранного заполнен.", sk_SK="Tento obsah nie je možné uložiť, pretože zoznam obľúbených\nje plný.", sl_SI="Te vsebine ni več mogoče shraniti. Seznam priljubljenih je\npoln.", sr_RS="Ovaj sadržaj se više ne može memorisati, jer je lista favorita\npopunjena.", sv_SE="Detta innehåll kunde inte sparas som favorit eftersom\nfavoritlistan är full.", tr_TR="Sık kullanılanlar listesi dolu olduğu için, artık bu içerik\nkaydedilemiyor.", uk_UA="Цей контент не можна зберегти, тому що список вибраного\nповний.")
texttool_globals_toast___function_not_available_because_privacy_mode_active = TextObject(bs_BA="Aktivirajte mobilne podatke za korištenje funkcije.", cs_CZ="Aktivujte prosím mobilní data, abyste mohli využívat funkci.", da_DK="Aktiver mobildata for at anvende funktion.", de_DE="Bitte aktiviere mobile Daten, um die Funktion zu nutzen.", el_GR="Ενεργοποιήστε τα δεδομένα κινητής τηλεφωνίας, για να\nχρησιμοποιήσετε τη λειτουργία.", en_GB="Please activate mobile data to use this function.", es_ES="Active los datos móviles para utilizar la función.", fi_FI="Aktivoi mobiilidata käyttääksesi toimintoa.", fr_FR="Veuillez activer les données mobiles pour pouvoir utiliser la\nfonction.", hr_HR="Aktivirajte mobilne podatke kako biste koristili funkciju.", hu_HU="Kérünk, a funkció aktiválásához aktiváld a mobil adatokat.", it_IT="Attivare i dati mobili per utilizzare la funzione.", nl_NL="Activeer mobiele gegevens om de functie te gebruiken.", no_NO="Aktiver mobildata for å bruke funksjonen.", pl_PL="Aby korzystać z funkcji, proszę włączyć dane mobilne.", pt_PT="Por favor, ative os dados móveis para utilizar a função.", ro_RO="Dezactivaţi datele mobile, pentru a utiliza funcţia.", ru_RU="Для использования функции активируйте мобильные данные.", sk_SK="Prosím, aktivujte mobilné dáta, aby ste mohli používať funkciu.", sl_SI="Za uporabo funkcije aktivirajte mobilne podatke.", sr_RS="Aktivirajte mobilne podatke da biste koristili funkciju.", sv_SE="Aktivera mobildata för att använda funktionen.", tr_TR="Fonksiyonu kullanmak için, lütfen mobil verieri etkinleştir.", uk_UA="Для використання функції активуйте мобільні дані.")
